        super(props);
        this.state = {
            editForm: false
        }
    }
    render() {
        const { user } = this.props;  

        return (
            <div className="user">
                <IoCloseCircleSharp onClick={() => this.props.onDelete(this.props.user.id)}className="delete-icon" />
                <IoHammerSharp onClick={() => {}}className="edit-icon" />  {/* ← было classNmae, исправлено */}
                <h3>{user.firstname} {user.lastname}</h3>
                <p>{user.bio}</p>
                <b>{user.isHappy ? 'Хапи' : 'Бедни'}</b>
            </div>
        )
    }
}

export default User
